const p = ($json.body && $json.body.payload) || {};
const texto = (p.body || "").trim();
const from = (p.from || "").replace("@c.us", "");

// ===== NÚMEROS AUTORIZADOS: poné acá los que pueden cargar (solo dígitos, con código de país) =====
const autorizados = ["5493510000001", "5493510000002", "5493510000003", "5493510000004"];

// Ignorar: mensajes propios, sin texto, o de números NO autorizados
if (p.fromMe || !texto || !autorizados.includes(from)) { return []; }

const reglas = "Extra\u00e9 datos de un mensaje de un taller gr\u00e1fico y devolv\u00e9 SOLO un JSON v\u00e1lido, sin explicaciones.\nClaves: empresa, contacto, descripcion, disciplina (uno de: laser, serigrafia, ploteo), precio (entero en pesos, 0 si no se menciona).\nRegla 'X de Y': X es el contacto (persona), Y es la empresa. Ej: 'marianela de andreu' => contacto 'Marianela', empresa 'Andreu'.\nJerga argentina de plata: luca/lucas = miles (80 lucas = 80000); palo = millon; gamba = 100.";
const prompt = reglas + "\nMensaje: " + texto;
return [{ json: { prompt, from } }];

let d = {};
try { d = JSON.parse($input.first().json.response || "{}"); } catch (e) { d = {}; }
const from = ($("Armar pedido").first().json.from || "").replace("@c.us","");
const nombre = d.contacto || d.empresa || "Sin nombre";
const disc = ["laser","serigrafia","ploteo"].includes(d.disciplina) ? d.disciplina : "laser";
return [{ json: {
  cliente: d.empresa ? (nombre + " (" + d.empresa + ")") : nombre,
  empresa_nombre: d.empresa || "",
  contacto_nombre: d.contacto || "",
  descripcion: d.descripcion || "",
  disciplina: disc,
  precio: Number(d.precio) || 0,
  origen_ref: "WhatsApp " + from
} }];
